import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.B9bl8Hm5.js";const P=JSON.parse('{"title":"网络 知识点","description":"","frontmatter":{},"headers":[],"relativePath":"network.md","filePath":"network.md"}'),r={name:"network.md"};function o(h,l,n,T,d,u){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="网络-知识点" tabindex="-1">网络 知识点 <a class="header-anchor" href="#网络-知识点" aria-label="Permalink to &quot;网络 知识点&quot;">​</a></h1><h2 id="_1-http-协议" tabindex="-1">1. HTTP 协议 <a class="header-anchor" href="#_1-http-协议" aria-label="Permalink to &quot;1. HTTP 协议&quot;">​</a></h2><ul><li>HTTP/1.0：每次请求都需要建立连接</li><li>HTTP/1.1：支持持久连接，流水线传输</li><li>HTTP/2：多路复用，服务器推送，头部压缩</li><li>HTTP/3：基于 QUIC 协议，更快的连接建立</li></ul><h2 id="_2-http-方法" tabindex="-1">2. HTTP 方法 <a class="header-anchor" href="#_2-http-方法" aria-label="Permalink to &quot;2. HTTP 方法&quot;">​</a></h2><ul><li>GET：获取资源</li><li>POST：提交数据</li><li>PUT：更新资源</li><li>DELETE：删除资源</li><li>PATCH：部分更新资源</li><li>HEAD：获取头部信息</li><li>OPTIONS：获取服务器支持的方法</li></ul><h2 id="_3-http-状态码" tabindex="-1">3. HTTP 状态码 <a class="header-anchor" href="#_3-http-状态码" aria-label="Permalink to &quot;3. HTTP 状态码&quot;">​</a></h2><ul><li>1xx：信息性状态码</li><li>2xx：成功状态码（200 OK, 201 Created）</li><li>3xx：重定向状态码（301 永久重定向, 302 临时重定向, 304 未修改）</li><li>4xx：客户端错误（400 错误请求, 401 未授权, 403 禁止访问, 404 未找到）</li><li>5xx：服务器错误（500 内部服务器错误, 503 服务不可用）</li></ul><h2 id="_4-https" tabindex="-1">4. HTTPS <a class="header-anchor" href="#_4-https" aria-label="Permalink to &quot;4. HTTPS&quot;">​</a></h2><ul><li>定义：HTTP + SSL/TLS 加密</li><li>作用：保证数据传输的安全性</li><li>证书：由 CA 颁发，验证服务器身份</li><li>握手过程：客户端和服务器协商加密算法和密钥</li></ul><h2 id="_5-跨域问题" tabindex="-1">5. 跨域问题 <a class="header-anchor" href="#_5-跨域问题" aria-label="Permalink to &quot;5. 跨域问题&quot;">​</a></h2><ul><li>同源策略：协议、域名、端口都相同</li><li>跨域解决方案： <ul><li>CORS（跨域资源共享）</li><li>JSONP</li><li>代理服务器</li><li>WebSocket</li><li>postMessage</li></ul></li></ul><h2 id="_6-网络请求优化" tabindex="-1">6. 网络请求优化 <a class="header-anchor" href="#_6-网络请求优化" aria-label="Permalink to &quot;6. 网络请求优化&quot;">​</a></h2><ul><li>减少请求数量：合并资源，使用精灵图</li><li>减少请求大小：压缩资源，使用 gzip</li><li>使用 CDN</li><li>缓存策略</li><li>预加载：<code>preload</code>, <code>prefetch</code></li><li>延迟加载：图片懒加载</li></ul><h2 id="_7-tcp-ip-协议" tabindex="-1">7. TCP/IP 协议 <a class="header-anchor" href="#_7-tcp-ip-协议" aria-label="Permalink to &quot;7. TCP/IP 协议&quot;">​</a></h2><ul><li>TCP：面向连接的可靠传输协议</li><li>IP：网络层协议，负责路由和寻址</li><li>TCP 三次握手：建立连接</li><li>TCP 四次挥手：关闭连接</li></ul><h2 id="_8-网络攻击" tabindex="-1">8. 网络攻击 <a class="header-anchor" href="#_8-网络攻击" aria-label="Permalink to &quot;8. 网络攻击&quot;">​</a></h2><ul><li>DDoS 攻击：分布式拒绝服务攻击</li><li>SQL 注入：注入恶意 SQL 语句</li><li>XSS：跨站脚本攻击</li><li>CSRF：跨站请求伪造</li><li>防范措施：输入验证、输出编码、使用 HTTPS 等</li></ul>',17)])])}const c=i(r,[["render",o]]);export{P as __pageData,c as default};
